  "type": "object",
  "properties": {
    "關鍵要點": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "列出所有關鍵要點"
    },
    "重要資訊": {
      "type": "object",
      "properties": {
        "測試距離": {
          "type": "string",
